     1→package com.grl.component.mapper;
     2→
     3→import com.google.common.collect.Multimap;
     4→import com.grl.component.asg.OntologyConstants;
     5→import com.grl.component.owl.Narrow;
     6→import com.grl.component.owl.OntologyUtil;
     7→import com.grl.component.owl.WithAnnotation;
     8→import com.grl.component.schema.PropertyNameResolver;
     9→import com.grl.component.schema.RestrictionInfo;
    10→import com.grl.component.schema.SchemaVisitor;
    11→import io.swagger.v3.oas.models.SpecVersion;
    12→import io.swagger.v3.oas.models.media.ObjectSchema;
    13→import io.swagger.v3.oas.models.media.Schema;
    14→import java.util.ArrayList;
    15→import java.util.Collection;
    16→import java.util.HashMap;
    17→import java.util.HashSet;
    18→import java.util.LinkedHashSet;
    19→import java.util.List;
    20→import java.util.Map;
    21→import java.util.Optional;
    22→import java.util.Set;
    23→import java.util.function.Predicate;
    24→import java.util.logging.Logger;
    25→import java.util.stream.Collectors;
    26→import java.util.stream.Stream;
    27→import javax.annotation.Nullable;
    28→import org.apache.commons.lang3.StringUtils;
    29→import org.semanticweb.owlapi.model.AsOWLClass;
    30→import org.semanticweb.owlapi.model.OWLClass;
    31→import org.semanticweb.owlapi.model.OWLClassExpression;
    32→import org.semanticweb.owlapi.model.OWLDataFactory;
    33→import org.semanticweb.owlapi.model.OWLDataProperty;
    34→import org.semanticweb.owlapi.model.OWLDataRestriction;
    35→import org.semanticweb.owlapi.model.OWLDatatype;
    36→import org.semanticweb.owlapi.model.OWLEntity;
    37→import org.semanticweb.owlapi.model.OWLLiteral;
    38→import org.semanticweb.owlapi.model.OWLNamedIndividual;
    39→import org.semanticweb.owlapi.model.OWLObjectProperty;
    40→import org.semanticweb.owlapi.model.OWLOntology;
    41→import org.semanticweb.owlapi.model.OWLSubClassOfAxiom;
    42→import org.semanticweb.owlapi.search.EntitySearcher;
    43→
    44→/**
    45→ * Maps an OWL class to an OpenAPI Schema object.
    46→ *
    47→ * <p>This mapper analyzes an OWL class from the ontology and generates a corresponding
    48→ * OpenAPI 3.1 ObjectSchema with properties derived from:
    49→ * <ul>
    50→ *   <li><b>Data properties</b> - mapped to primitive schema types (string, integer, etc.)</li>
    51→ *   <li><b>Object properties</b> - mapped to $ref references or inline schemas</li>
    52→ *   <li><b>Taxonomy properties</b> - mapped to enum schemas based on named individuals</li>
    53→ * </ul>
    54→ *
    55→ * <h2>Processing Pipeline</h2>
    56→ * <pre>
    57→ * OWLClass → SchemaVisitors → Axiom Collection → Restriction Merging
    58→ *                                    ↓
    59→ *         ┌────────────────────────────────────────────┐
    60→ *         │                                            │
    61→ *         ▼                    ▼                       ▼
    62→ *   DataPropertyMapper   ObjectPropertyMapper   TaxonomyPropertyMapper
    63→ *         │                    │                       │
    64→ *         └────────────────────┴───────────────────────┘
    65→ *                              ↓
    66→ *                      OpenAPI ObjectSchema
    67→ * </pre>
    68→ *
    69→ * <h2>Annotation Filtering</h2>
    70→ * <p>Only axioms annotated with {@code apiLabel} matching the schema label from
    71→ * {@link MappingContext#getSchemaLabel()} are included in the generated schema.
    72→ *
    73→ * <h2>Thread Safety</h2>
    74→ * <p>This class is <b>not thread-safe</b>. Each instance should be used to map
    75→ * a single OWL class and then discarded.
    76→ *
    77→ * @see DataPropertyMapper
    78→ * @see ObjectPropertyMapper
    79→ * @see TaxonomyPropertyMapper
    80→ * @see SchemaVisitor
    81→ */
    82→public class ResourceSchemaMapper {
    83→
    84→  /**
    85→   * Holds paired SchemaVisitors for analyzing object and data property restrictions.
    86→   *
    87→   * @param objectPropertyVisitor visitor that collects object property restrictions
    88→   * @param dataPropertyVisitor visitor that collects data property restrictions
    89→   */
    90→  private record VisitorPair(SchemaVisitor objectPropertyVisitor, SchemaVisitor dataPropertyVisitor) {}
    91→
    92→  /**
    93→   * Holds categorized axiom collections for the analyzed class.
    94→   *
    95→   * @param taxonomy axioms referencing named individuals (enum values)
    96→   * @param subClass direct SubClassOf axioms for the analyzed class
    97→   * @param superClass inherited axioms from the class hierarchy
    98→   */
    99→  private record AxiomCollection(
   100→      List<OWLSubClassOfAxiom> taxonomy,
   101→      List<OWLSubClassOfAxiom> subClass,
   102→      List<OWLSubClassOfAxiom> superClass) {}
   103→  private static final Logger logger = Logger.getLogger(ResourceSchemaMapper.class.getName());
   104→  private final MappingContext context;
   105→  private final PropertyNameResolver nameResolver = new PropertyNameResolver();
   106→  private final String type;
   107→  private final OWLClass cls;
   108→  private final String classDescription;
   109→  private final String name;
   110→  private final Schema<?> schema;
   111→
   112→  public Schema<?> getSchema() {
   113→    return schema;
   114→  }
   115→
   116→  public String getName() {
   117→    return name;
   118→  }
   119→
   120→  public ResourceSchemaMapper(MappingContext context, OWLClass cls, String clsDescription) {
   121→    this.context = context;
   122→    this.cls = cls;
   123→    this.classDescription = clsDescription;
   124→    this.type = "object";
   125→    this.name = nameResolver.resolve(cls);
   126→    this.schema = createSchema(cls);
   127→  }
   128→
   129→  /**
   130→   * Creates the OpenAPI schema for the analyzed OWL class.
   131→   *
   132→   * <p>This method orchestrates the schema generation by:
   133→   * <ol>
   134→   *   <li>Initializing the base ObjectSchema with metadata</li>
   135→   *   <li>Creating visitors to traverse class restrictions</li>
   136→   *   <li>Collecting relevant axioms from the ontology</li>
   137→   *   <li>Visiting axioms to gather property restrictions</li>
   138→   *   <li>Processing data, object, and taxonomy properties</li>
   139→   * </ol>
   140→   *
   141→   * @param analyzedClass the OWL class to generate a schema for
   142→   * @return the generated OpenAPI Schema object
   143→   */
   144→  private Schema<?> createSchema(OWLClass analyzedClass) {
   145→    Schema<?> schema = initializeResourceSchema();
   146→
   147→    VisitorPair visitors = createSchemaVisitors(analyzedClass);
   148→    AxiomCollection axioms = collectRelevantAxioms(analyzedClass);
   149→
   150→    visitAxiomsWithVisitors(visitors, axioms);
   151→
   152→    Map<String, Set<RestrictionInfo>> restrictions = mergeVisitorRestrictions(visitors);
   153→
   154→    processDataProperties(schema, visitors.dataPropertyVisitor(), restrictions, axioms.subClass());
   155→    processObjectProperties(schema, visitors.objectPropertyVisitor(), restrictions);
   156→    processTaxonomyProperties(schema, axioms.taxonomy());
   157→
   158→    if (schema.getProperties() == null || schema.getProperties().isEmpty()) {
   159→      logMissingPropertiesWarning(analyzedClass, axioms);
   160→    }
   161→
   162→    return schema;
   163→  }
   164→
   165→  /**
   166→   * Creates and configures the base ObjectSchema with standard properties.
   167→   *
   168→   * @return a new ObjectSchema configured with name, type, description, and OpenAPI 3.1 spec version
   169→   */
   170→  private Schema<?> initializeResourceSchema() {
   171→    Schema<?> resourceSchema = new ObjectSchema();
   172→    resourceSchema.setSpecVersion(SpecVersion.V31);
   173→    resourceSchema.setName(this.name);
   174→    resourceSchema.setDescription(this.classDescription);
   175→    resourceSchema.setType(this.type);
   176→    resourceSchema.setAdditionalProperties(false);
   177→    resourceSchema.setTitle(getLabel(this.cls));
   178→    return resourceSchema;
   179→  }
   180→
   181→  /**
   182→   * Creates paired SchemaVisitors for analyzing object and data property restrictions.
   183→   *
   184→   * <p>Both visitors traverse the same class hierarchy but collect different types
   185→   * of restrictions:
   186→   * <ul>
   187→   *   <li>Object visitor: collects SomeValuesFrom, AllValuesFrom, cardinality on object properties</li>
   188→   *   <li>Data visitor: collects DataSomeValuesFrom, DataAllValuesFrom, cardinality on data properties</li>
   189→   * </ul>
   190→   *
   191→   * @param analyzedClass the OWL class to analyze
   192→   * @return a record containing both configured visitors
   193→   */
   194→  private VisitorPair createSchemaVisitors(OWLClass analyzedClass) {
   195→    OWLDataFactory dataFactory = context.getManager().getOWLDataFactory();
   196→    OWLClass owlThing = dataFactory.getOWLThing();
   197→    return new VisitorPair(
   198→        new SchemaVisitor(analyzedClass, context.getOntology(), owlThing, "", false),
   199→        new SchemaVisitor(analyzedClass, context.getOntology(), owlThing, "", false));
   200→  }
   201→
   202→  /**
   203→   * Collects all relevant axioms for the analyzed class from the ontology.
   204→   *
   205→   * <p>Gathers three categories of axioms:
   206→   * <ul>
   207→   *   <li><b>Taxonomy axioms</b>: SubClassOf axioms referencing named individuals (enum values)</li>
   208→   *   <li><b>SubClass axioms</b>: Direct SubClassOf axioms for the analyzed class</li>
   209→   *   <li><b>SuperClass axioms</b>: Inherited axioms from the class hierarchy</li>
   210→   * </ul>
   211→   *
   212→   * @param analyzedClass the OWL class to collect axioms for
   213→   * @return a record containing categorized axiom lists
   214→   */
   215→  private AxiomCollection collectRelevantAxioms(OWLClass analyzedClass) {
   216→    OWLOntology ontology = context.getOntology();
   217→    return new AxiomCollection(
   218→        getTaxonomyAxioms(analyzedClass),
   219→        ontology.subClassAxiomsForSubClass(analyzedClass).toList(),
   220→        getSuperClassAxioms(analyzedClass, null).toList());
   221→  }
   222→
   223→  /**
   224→   * Visits axioms with the appropriate schema visitors to collect restrictions.
   225→   *
   226→   * <p>For each axiom, the superclass expression is visited by the object property
   227→   * visitor if it contains object properties, and by the data property visitor if
   228→   * it contains data properties.
   229→   *
   230→   * @param visitors the visitor pair to use
   231→   * @param axioms the axiom collection to process
   232→   */
   233→  private void visitAxiomsWithVisitors(VisitorPair visitors, AxiomCollection axioms) {
   234→    String schemaLabel = context.getSchemaLabel();
   235→
   236→    // Filter axioms to only those annotated with the target apiLabel
   237→    // This allows multiple API schemas to be generated from the same ontology
   238→    axioms.subClass().stream()
   239→        .filter(axiom -> !axioms.taxonomy().contains(axiom))
   240→        .filter(WithAnnotation.of(OntologyConstants.apiLabel, schemaLabel))
   241→        .map(OWLSubClassOfAxiom::getSuperClass)
   242→        .forEach(superClass -> visitSuperClass(superClass, visitors));
   243→
   244→    axioms.superClass().stream()
   245→        .map(OWLSubClassOfAxiom::getSuperClass)
   246→        .forEach(superClass -> visitSuperClass(superClass, visitors));
   247→  }
   248→
   249→  /**
   250→   * Visits a superclass expression with the appropriate visitors based on property types.
   251→   *
   252→   * @param superClass the class expression to visit
   253→   * @param visitors the visitor pair
   254→   */
   255→  private void visitSuperClass(OWLClassExpression superClass, VisitorPair visitors) {
   256→    if (!superClass.getObjectPropertiesInSignature().isEmpty()) {
   257→      superClass.accept(visitors.objectPropertyVisitor());
   258→    }
   259→    if (!superClass.getDataPropertiesInSignature().isEmpty()) {
   260→      superClass.accept(visitors.dataPropertyVisitor());
   261→    }
   262→  }
   263→
   264→  /**
   265→   * Merges typed restrictions from both schema visitors into a unified map.
   266→   *
   267→   * <p>Combines restrictions keyed by property name. A single property may have
   268→   * multiple restrictions (e.g., both minCardinality and maxCardinality).
   269→   *
   270→   * @param visitors the visitor pair containing collected restrictions
   271→   * @return map of property name → set of RestrictionInfo for that property
   272→   */
   273→  private Map<String, Set<RestrictionInfo>> mergeVisitorRestrictions(VisitorPair visitors) {
   274→    Map<String, Set<RestrictionInfo>> restrictions = new HashMap<>();
   275→    Stream.of(visitors.objectPropertyVisitor(), visitors.dataPropertyVisitor())
   276→        .map(SchemaVisitor::getRestrictions)
   277→        .flatMap(map -> map.entrySet().stream())
   278→        .forEach(entry -> restrictions.computeIfAbsent(entry.getKey(), k -> new LinkedHashSet<>())
   279→            .addAll(entry.getValue()));
   280→    return restrictions;
   281→  }
   282→
   283→  /**
   284→   * Finds a data property in the ontology by its resolved name.
   285→   *
   286→   * @param propertyName the short-form property name (e.g., "firstName")
   287→   * @return the matching OWLDataProperty, or empty if not found
   288→   */
   289→  private Optional<OWLDataProperty> findDataProperty(String propertyName) {
   290→    return context.getOntology()
   291→        .getDataPropertiesInSignature().stream()
   292→        .filter(prop -> nameResolver.resolve(prop).equals(propertyName))
   293→        .findFirst();
   294→  }
   295→
   296→  /**
   297→   * Finds an object property in the ontology by its resolved name.
   298→   *
   299→   * @param propertyName the short-form property name (e.g., "hasAddress")
   300→   * @return the matching OWLObjectProperty, or empty if not found
   301→   */
   302→  private Optional<OWLObjectProperty> findObjectProperty(String propertyName) {
   303→    return context.getOntology()
   304→        .getObjectPropertiesInSignature().stream()
   305→        .filter(prop -> nameResolver.resolve(prop).equals(propertyName))
   306→        .findFirst();
   307→  }
   308→
   309→  /**
   310→   * Extracts range type/class names for a property from multiple sources.
   311→   *
   312→   * <p>Ranges are collected from:
   313→   * <ol>
   314→   *   <li>The SchemaVisitor's property range multimap (from restriction fillers)</li>
   315→   *   <li>The RestrictionInfo objects themselves (via getRangeNames)</li>
   316→   * </ol>
   317→   *
   318→   * @param propertyName the property to extract ranges for
   319→   * @param rangesFromVisitor multimap of property → range classes/datatypes from visitor
   320→   * @param restrictions map of property → RestrictionInfo set
   321→   * @return deduplicated list of range type names
   322→   */
   323→  private List<String> extractPropertyRanges(
   324→      String propertyName,
   325→      Multimap<String, ? extends OWLEntity> rangesFromVisitor,
   326→      Map<String, Set<RestrictionInfo>> restrictions) {
   327→    List<String> ranges = new ArrayList<>();
   328→
   329→    // Extract from visitor's range multimap
   330→    rangesFromVisitor.get(propertyName).stream()
   331→        .map(nameResolver::resolve)
   332→        .forEach(ranges::add);
   333→
   334→    // Also extract from restrictions themselves
   335→    Set<RestrictionInfo> propertyRestrictions = restrictions.getOrDefault(propertyName, Set.of());
   336→    propertyRestrictions.stream()
   337→        .flatMap(r -> r.getRangeNames(nameResolver).stream())
   338→        .forEach(ranges::add);
   339→
   340→    // Remove duplicates to avoid treating single-range properties as multi-range
   341→    return ranges.stream().distinct().toList();
   342→  }
   343→
   344→  /**
   345→   * Extracts the example value for a data property from annotations.
   346→   *
   347→   * <p>Looks for skos:example annotations in two places (in order):
   348→   * <ol>
   349→   *   <li>On the SubClassOf axiom containing the property restriction</li>
   350→   *   <li>On the data property itself (as a default)</li>
   351→   * </ol>
   352→   *
   353→   * @param dataProperty the data property to find an example for
   354→   * @param subClassAxioms axioms that may contain restriction-level annotations
   355→   * @return the example value string, or null if none found
   356→   */
   357→  private String extractExampleValue(OWLDataProperty dataProperty, List<OWLSubClassOfAxiom> subClassAxioms) {
   358→    // First, look for a skos:example annotation on the restriction axiom itself
   359→    return subClassAxioms.stream()
   360→        .filter(axiom ->
   361→            axiom.getSuperClass() instanceof OWLDataRestriction restriction
   362→                && restriction.getProperty().asOWLDataProperty().getIRI().equals(dataProperty.getIRI()))
   363→        .map(axiom -> axiom.getAnnotations().stream()
   364→            .filter(annotation -> annotation.getProperty().getIRI().equals(OntologyConstants.SKOS_EXAMPLE))
   365→            .findFirst()
   366→            .flatMap(annotation -> annotation.mapLiteral(OWLLiteral::getLiteral)))
   367→        .flatMap(Optional::stream)
   368→        .findFirst()
   369→        // Fall back to the annotation on the data property itself
   370→        .orElse(OntologyUtil.defaultAnnotationsOf(dataProperty, context.getOntology())
   371→            .getOrDefault(OntologyConstants.SKOS_EXAMPLE.getShortForm(), null));
   372→  }
   373→
   374→  /**
   375→   * Processes all data properties and adds them to the schema.
   376→   *
   377→   * <p>For each data property discovered by the SchemaVisitor:
   378→   * <ol>
   379→   *   <li>Looks up the OWLDataProperty in the ontology</li>
   380→   *   <li>Extracts description, label, example, ranges, and enum values</li>
   381→   *   <li>Creates a DataPropertyMapper to generate the schema</li>
   382→   *   <li>Adds the property to the resource schema</li>
   383→   *   <li>Marks as required if restrictions indicate requiredness</li>
   384→   * </ol>
   385→   *
   386→   * @param schema the resource schema to add properties to
   387→   * @param dataVisitor visitor containing data property information
   388→   * @param restrictions merged restrictions map
   389→   * @param subClassAxioms axioms for extracting example annotations
   390→   */
   391→  private void processDataProperties(
   392→      Schema<?> schema,
   393→      SchemaVisitor dataVisitor,
   394→      Map<String, Set<RestrictionInfo>> restrictions,
   395→      List<OWLSubClassOfAxiom> subClassAxioms) {
   396→
   397→    Multimap<String, OWLDatatype> dataPropertyRanges = dataVisitor.getDataPropertyRanges();
   398→    Set<String> dataPropertyNames = dataVisitor.getDataPropertyNames();
   399→
   400→    for (String propertyName : dataPropertyNames) {
   401→      Optional<OWLDataProperty> dataPropertyOpt = findDataProperty(propertyName);
   402→      if (dataPropertyOpt.isEmpty()) {
   403→        continue;
   404→      }
   405→
   406→      OWLDataProperty dataProperty = dataPropertyOpt.get();
   407→      Set<RestrictionInfo> propertyRestrictions = restrictions.getOrDefault(propertyName, Set.of());
   408→
   409→      String propertyDescription = OntologyUtil.getDescription(dataProperty, context.getOntology());
   410→      String label = getLabel(dataProperty);
   411→      String exampleValue = extractExampleValue(dataProperty, subClassAxioms);
   412→      List<String> rangeTypes = extractPropertyRanges(propertyName, dataPropertyRanges, restrictions);
   413→      List<String> enumValues = propertyRestrictions.stream()
   414→          .flatMap(r -> r.getEnumValues().stream())
   415→          .toList();
   416→
   417→      DataPropertyMapper mapper = new DataPropertyMapper(
   418→          context.getConfig(),
   419→          nameResolver.resolve(dataProperty),
   420→          label,
   421→          propertyDescription,
   422→          exampleValue,
   423→          propertyRestrictions,
   424→          enumValues,
   425→          rangeTypes);
   426→
   427→      try {
   428→        schema.addProperty(mapper.getName(), mapper.getSchemaByDataProperty());
   429→        if (mapper.isRequired()) {
   430→          schema.addRequiredItem(mapper.getName());
   431→        }
   432→      } catch (Exception e) {
   433→        throw new RuntimeException("Error when processing data property " + mapper.getName(), e);
   434→      }
   435→    }
   436→  }
   437→
   438→  /**
   439→   * Processes all object properties and adds them to the schema.
   440→   *
   441→   * <p>For each object property discovered by the SchemaVisitor:
   442→   * <ol>
   443→   *   <li>Looks up the OWLObjectProperty in the ontology</li>
   444→   *   <li>Extracts description, label, and range classes</li>
   445→   *   <li>Creates an ObjectPropertyMapper to generate the schema</li>
   446→   *   <li>Adds the property to the resource schema</li>
   447→   *   <li>Marks as required if restrictions indicate requiredness</li>
   448→   * </ol>
   449→   *
   450→   * @param schema the resource schema to add properties to
   451→   * @param objectVisitor visitor containing object property information
   452→   * @param restrictions merged restrictions map
   453→   */
   454→  private void processObjectProperties(
   455→      Schema<?> schema,
   456→      SchemaVisitor objectVisitor,
   457→      Map<String, Set<RestrictionInfo>> restrictions) {
   458→
   459→    Multimap<String, OWLClass> objectPropertyRanges = objectVisitor.getObjectPropertyRanges();
   460→    Set<String> objectPropertyNames = objectVisitor.getObjectPropertyNames();
   461→
   462→    for (String propertyName : objectPropertyNames) {
   463→      Optional<OWLObjectProperty> objectPropertyOpt = findObjectProperty(propertyName);
   464→      if (objectPropertyOpt.isEmpty()) {
   465→        continue;
   466→      }
   467→
   468→      OWLObjectProperty objectProperty = objectPropertyOpt.get();
   469→      Set<RestrictionInfo> propertyRestrictions = restrictions.getOrDefault(propertyName, Set.of());
   470→
   471→      String propertyDescription = OntologyUtil.getDescription(objectProperty, context.getOntology());
   472→      String propertyLabel = getLabel(objectProperty);
   473→      List<String> rangeClasses = extractPropertyRanges(propertyName, objectPropertyRanges, restrictions);
   474→
   475→      ObjectPropertyMapper mapper = new ObjectPropertyMapper(
   476→          context, propertyName, propertyLabel, propertyDescription, propertyRestrictions, rangeClasses);
   477→
   478→      schema.addProperty(mapper.getName(), mapper.getSchema());
   479→      if (mapper.isRequired()) {
   480→        schema.addRequiredItem(mapper.getName());
   481→      }
   482→    }
   483→  }
   484→
   485→  /**
   486→   * Processes taxonomy axioms and adds enum properties to the schema.
   487→   *
   488→   * <p>Taxonomy properties are object properties whose range is a set of named
   489→   * individuals (enum values). These are mapped to StringSchema with enum constraints.
   490→   *
   491→   * <p>Two patterns are supported:
   492→   * <ul>
   493→   *   <li><b>Direct individuals</b>: The restriction directly references named individuals</li>
   494→   *   <li><b>Class-based</b>: The restriction references a class, and individuals are
   495→   *       looked up via EntitySearcher</li>
   496→   * </ul>
   497→   *
   498→   * @param schema the resource schema to add taxonomy properties to
   499→   * @param taxonomyAxioms axioms identified as taxonomy definitions
   500→   */
   501→  private void processTaxonomyProperties(Schema<?> schema, List<OWLSubClassOfAxiom> taxonomyAxioms) {
   502→    Set<OWLObjectProperty> taxonomyPropertyNames = taxonomyAxioms.stream()
   503→        .map(OWLSubClassOfAxiom::getSuperClass)
   504→        .flatMap(superCls -> superCls.getObjectPropertiesInSignature().stream())
   505→        .collect(Collectors.toSet());
   506→
   507→    for (OWLObjectProperty taxonomyProperty : taxonomyPropertyNames) {
   508→      for (OWLSubClassOfAxiom axiom : taxonomyAxioms) {
   509→        OWLClassExpression superCls = axiom.getSuperClass();
   510→
   511→        for (OWLObjectProperty objectProperty : superCls.getObjectPropertiesInSignature()) {
   512→          if (!objectProperty.equals(taxonomyProperty)) {
   513→            continue;
   514→          }
   515→
   516→          Set<RestrictionInfo> taxonomyRestrictions = new LinkedHashSet<>();
   517→          RestrictionInfo.from(superCls).ifPresent(taxonomyRestrictions::add);
   518→
   519→          // Taxonomy detection: check if axiom references named individuals directly
   520→          Set<OWLNamedIndividual> individualsInSignature = superCls.getIndividualsInSignature();
   521→
   522→          if (!individualsInSignature.isEmpty()) {
   523→            // Direct individual reference - use individual labels as enum values
   524→            addTaxonomyPropertyToSchema(schema,
   525→                nameResolver.resolve(taxonomyProperty),
   526→                OntologyUtil.getDescription(cls, context.getOntology()),
   527→                getLabel(taxonomyProperty),
   528→                individualsInSignature.stream().map(this::getLabel).toList(),
   529→                taxonomyRestrictions);
   530→          } else {
   531→            // Indirect reference via class - look up individuals belonging to the class
   532→            for (OWLClass taxonomyClass : superCls.getClassesInSignature()) {
   533→              List<OWLNamedIndividual> individuals = EntitySearcher
   534→                  .getIndividuals(taxonomyClass, context.getOntology())
   535→                  .flatMap(Narrow.to(OWLNamedIndividual.class))
   536→                  .toList();
   537→
   538→              addTaxonomyPropertyToSchema(schema,
   539→                  taxonomyName(nameResolver.resolve(taxonomyClass)),
   540→                  OntologyUtil.getDescription(taxonomyClass, context.getOntology()),
   541→                  getLabel(taxonomyClass),
   542→                  individuals.stream().map(this::getLabel).toList(),
   543→                  taxonomyRestrictions);
   544→            }
   545→          }
   546→        }
   547→      }
   548→    }
   549→  }
   550→
   551→  /**
   552→   * Adds a taxonomy property to the schema.
   553→   *
   554→   * @param schema the schema to add the property to
   555→   * @param name the property name
   556→   * @param description the property description
   557→   * @param label the property label
   558→   * @param enumValues the list of allowed enum values
   559→   * @param restrictions the restrictions for this property
   560→   */
   561→  private void addTaxonomyPropertyToSchema(
   562→      Schema<?> schema,
   563→      String name,
   564→      String description,
   565→      String label,
   566→      List<String> enumValues,
   567→      Set<RestrictionInfo> restrictions) {
   568→    TaxonomyPropertyMapper mapper = new TaxonomyPropertyMapper(
   569→        context, name, description, label, enumValues, restrictions);
   570→    schema.addProperty(mapper.getName(), mapper.getTaxonomySchemaObject());
   571→    if (mapper.isRequired()) {
   572→      schema.addRequiredItem(mapper.getName());
   573→    }
   574→  }
   575→
   576→  /**
   577→   * Logs a warning when no properties were found for a class.
   578→   *
   579→   * <p>This typically indicates that the ontology is missing apiLabel annotations
   580→   * on the property restrictions, or that the schema label doesn't match.
   581→   *
   582→   * @param analyzedClass the class that had no mappable properties
   583→   * @param axioms all collected axioms (for diagnostic output)
   584→   */
   585→  private void logMissingPropertiesWarning(OWLClass analyzedClass, AxiomCollection axioms) {
   586→    logger.warning("No properties with " + OntologyConstants.apiLabel
   587→        + " annotation found for: " + analyzedClass);
   588→
   589→    List<OWLSubClassOfAxiom> allAxioms = Stream.of(axioms.superClass(), axioms.subClass(), axioms.taxonomy())
   590→        .flatMap(Collection::stream)
   591→        .toList();
   592→
   593→    if (!allAxioms.isEmpty()) {
   594→      allAxioms.stream()
   595→          .map(axiom -> axiom.getSuperClass().toString())
   596→          .forEach(s -> logger.warning("\tPossible property: " + s));
   597→    }
   598→  }
   599→
   600→  private List<OWLSubClassOfAxiom> getTaxonomyAxioms(OWLClass analyzedClass) {
   601→    Set<OWLSubClassOfAxiom> subAx = context.getOntology().getSubClassAxiomsForSubClass(analyzedClass);
   602→    String schemaAnnotation = getSchemaAnnotation(context.getSchemaLabel());
   603→
   604→    return subAx.stream().filter(ax -> ax.annotations()
   605→        .anyMatch(annotation -> annotation.getValue().toString().equals(schemaAnnotation))).filter(ax -> {
   606→      OWLClassExpression superCls = ax.getSuperClass();
   607→      return !superCls.getObjectPropertiesInSignature().isEmpty() && (superCls.individualsInSignature()
   608→          .anyMatch(individual -> !EntitySearcher.getObjectPropertyValues(individual, context.getOntology())
   609→              .isEmpty()) || superCls.classesInSignature()
   610→          .anyMatch(cls -> EntitySearcher.getIndividuals(cls, context.getOntology()).findAny().isPresent()));
   611→    }).collect(Collectors.toList());
   612→  }
   613→
   614→  public String getSchemaName() {
   615→    return nameResolver.resolve(cls);
   616→  }
   617→
   618→  private String getSchemaAnnotation(String schema) {
   619→    return '"' + schema + '"' + "^^xsd:string";
   620→  }
   621→
   622→  private String taxonomyName(String taxonomy_name) {
   623→    if (StringUtils.countMatches(taxonomy_name, "_") > 0) {
   624→      return taxonomy_name.substring(taxonomy_name.lastIndexOf("_") + 1);
   625→    }
   626→    return taxonomy_name.substring(0, 1).toUpperCase() + taxonomy_name.substring(1);
   627→  }
   628→
   629→  private String getLabel(final OWLEntity entity) {
   630→    return OntologyUtil.getTitle(entity, context.getOntology());
   631→  }
   632→
   633→  private Stream<OWLSubClassOfAxiom> getSuperClassAxioms(OWLClass analyzedClass,
   634→                                                         @Nullable Set<OWLClass> ignoreClasses) {
   635→    final Set<OWLClass> processedClasses = Optional.ofNullable(ignoreClasses).orElse(new HashSet<OWLClass>());
   636→    final String schemaAnnotation = getSchemaAnnotation(context.getSchemaLabel());
   637→    return context.getOntology().subClassAxiomsForSubClass(analyzedClass)
   638→        .filter(WithAnnotation.of(OntologyConstants.apiLabel, context.getSchemaLabel()))
   639→        .map(OWLSubClassOfAxiom::getSuperClass).filter(OWLClassExpression::isOWLClass).map(AsOWLClass::asOWLClass)
   640→        .filter(Predicate.not(processedClasses::contains)).peek(processedClasses::add) // side effect
   641→        .flatMap(context.getOntology()::subClassAxiomsForSubClass).flatMap(owlSubClassOfAxiom -> {
   642→          final OWLClassExpression superClass = owlSubClassOfAxiom.getSuperClass();
   643→          final List<OWLSubClassOfAxiom> superClassAxioms = new ArrayList<>();
   644→          if (superClass.isOWLClass()) {
   645→            getSuperClassAxioms(superClass.asOWLClass(), processedClasses).forEach(superClassAxioms::add);
   646→          }
   647→          if (owlSubClassOfAxiom.annotations()
   648→              .anyMatch(owlAnnotation -> owlAnnotation.getValue().toString().equals(schemaAnnotation))) {
   649→            superClassAxioms.add(owlSubClassOfAxiom);
   650→          }
   651→          return superClassAxioms.stream();
   652→        });
   653→  }
   654→
   655→}
