    85→        restriction.applyToArraySchema(array);
    86→      }
    87→      Schema itemSchema = referenceSchema.orElseGet(() -> new ComposedSchema().$ref(ref));
    88→      array.items(itemSchema);
    89→      return array;
    90→    } else {
    91→      // For a single item reference, use allOf: [ referenceschema ]
    92→      Schema<?> allOfItems = new ArraySchema().type(null)
    93→          .items(referenceSchema.orElseGet(() -> new ComposedSchema().$ref(ref)));
    94→      // NOTE: someValuesFrom/allValuesFrom don't require special handling for non-array refs
    95→      // HasValue restrictions would need special handling if encountered
    96→      if (CollectionUtils.isNotEmpty(allOfItems.getAllOf())) {
    97→        if (allOfItems.getAllOf().size() > 1) {
    98→          return new ComposedSchema().allOf(List.of(allOfItems));
    99→        } else {
   100→          return allOfItems.getAllOf().getFirst();
   101→        }
   102→      } else {
   103→        return allOfItems.getItems();
   104→      }
   105→    }
   106→  }
   107→
   108→  private Schema getComposedSchemaObject(List<String> refs, boolean isArray) {
   109→    ObjectSchema rangeObjectSchema = new ObjectSchema();
   110→    Map<String, Schema> rangeProperties = new HashMap<>();
   111→
   112→    // Create a schema reference for each of the given references
   113→    for (String ref : refs) {
   114→      // create schema for referenced class
   115→      context.addSchema(ref);
   116→      OWLClass rangeCls = context.getManager().getOWLDataFactory()
   117→          .getOWLClass(IRI.create(context.getDefaultOntologyPrefixIRI() + ref));
   118→      String rangeDescription = OntologyUtil.getDescription(rangeCls, context.getOntology());
   119→      Schema<?> rangePropertiesSchema = mapLinkedResourceClass(rangeCls).orElseGet(() -> {
   120→        ResourceSchemaMapper rangeSchema = new ResourceSchemaMapper(context, rangeCls, rangeDescription);
   121→        Schema childSchema = new ComposedSchema();
   122→        childSchema.setName(rangeSchema.getSchemaName());
   123→        childSchema.setDescription(rangeDescription);
   124→        childSchema.set$ref(ref);
   125→        return childSchema;
   126→      });
   127→      rangePropertiesSchema.setTitle(OntologyUtil.getTitle(rangeCls, context.getOntology()));
   128→      rangeProperties.put(ref, rangePropertiesSchema);
   129→    }
   130→    rangeObjectSchema.setAdditionalProperties(false);
   131→    rangeObjectSchema.setProperties(rangeProperties);
   132→
   133→    if (!isArray) {
   134→      // Is singular
   135→      return rangeObjectSchema;
   136→    } else {
   137→      ArraySchema arraySchema = new ArraySchema();
   138→      arraySchema.setType("array");
   139→      arraySchema.setDescription(this.description);
   140→      arraySchema.setItems(rangeObjectSchema);
   141→      arraySchema.setType("array");
   142→      // NEW: Use typed restrictions (Phase 4)
   143→      for (RestrictionInfo restriction : this.restrictions) {
   144→        restriction.applyToArraySchema(arraySchema);
   145→      }
   146→      return arraySchema;
   147→    }
   148→  }
   149→
   150→  public String getName() {
   151→    return name;
   152→  }
   153→
   154→  /**
   155→   * Check whether given class is a fully addressable item in our model - if so will have its own identifier field
   156→   * and be exposed
   157→   * as an api resource.
   158→   * The returned schema contains an extension field x-grl-model-link with the string value of the API model name the
   159→   * id refers too
   160→   *
   161→   * @param cls class to check
   162→   * @return schema for identifier if a fully addressable model item (i.e. has an id field etc)
   163→   * @throws RuntimeException if the determined identifier class does not have a single uniqueText data property
   164→   */
   165→  private Optional<Schema> mapLinkedResourceClass(OWLClass cls) {
   166→    if (context.getResourceClasses().contains(cls)) {
   167→      final OWLOntology ontology = context.getOntology();
   168→      return EntitySearcher.getSuperClasses(cls, ontology).flatMap(Narrow.to(HasProperty.class))
   169→          .filter(WithIRI.onPropertyOf(OntologyConstants.apiID)).findFirst()
   170→          .map(identifierClass -> {
   171→            // Check ontology of id class found
   172→            return new StringSchema().extensions(
   173→                    Map.of(OpenApiConstants.X_GRL_MODEL_LINK, nameResolver.resolve(cls)))
   174→                .description("Unique identifier of " + nameResolver.resolve(cls))
   175→                .example(nameResolver.resolve(cls) + "-12345");
   176→
   177→          });
   178→    } else
   179→      return Optional.empty();
   180→  }
   181→}
