    67→  public OWLOntologyManager getManager() {
    68→    return manager;
    69→  }
    70→
    71→
    72→  /**
    73→   * If not in context cache already, create schema for given class and add to cache
    74→   *
    75→   * @param shortName shortname of class
    76→   */
    77→  public void addSchema(String shortName) {
    78→    schemaByRef.computeIfAbsent(shortName, s -> {
    79→      if (!computing.contains(s)) {
    80→        computing.add(s);
    81→        try {
    82→          OWLClass cls = manager.getOWLDataFactory().getOWLClass(IRI.create(defaultOntologyPrefixIRI + shortName));
    83→          String description = OntologyUtil.getDescription(cls, ontology);
    84→          ResourceSchemaMapper resourceSchemaMapper = new ResourceSchemaMapper(this, cls, description);
    85→          return resourceSchemaMapper.getSchema();
    86→        } finally {
    87→          computing.remove(s);
    88→        }
    89→      } else
    90→        return null; // already being computed, ignore to avoid infinite recursion
    91→    });
    92→  }
    93→
    94→  public Set<OWLClass> getResourceClasses() {
    95→    return resourceClasses;
    96→  }
    97→
    98→
    99→}
