   197→  /**
   198→   * Apply this restriction to an ArraySchema with correct OWL→OpenAPI semantics.
   199→   *
   200→   * @param schema the ArraySchema to apply restrictions to
   201→   */
   202→  default void applyToArraySchema(io.swagger.v3.oas.models.media.ArraySchema schema) {
   203→    switch (this) {
   204→      case MinCardinality r -> schema.setMinItems(r.expression().getCardinality());
   205→      case MaxCardinality r -> schema.setMaxItems(r.expression().getCardinality());
   206→      case ExactCardinality r -> {
   207→        schema.setMinItems(r.expression().getCardinality());
   208→        schema.setMaxItems(r.expression().getCardinality());
   209→      }
   210→      case DataMinCardinality r -> schema.setMinItems(r.expression().getCardinality());
   211→      case DataMaxCardinality r -> schema.setMaxItems(r.expression().getCardinality());
   212→      case DataExactCardinality r -> {
   213→        schema.setMinItems(r.expression().getCardinality());
   214→        schema.setMaxItems(r.expression().getCardinality());
   215→      }
   216→      case SomeValuesFrom r -> {
   217→        // someValuesFrom = "at least one from this set"
   218→        // Set minItems=1, NO maxItems
   219→        schema.setMinItems(1);
   220→      }
   221→      case AllValuesFrom r -> {
   222→        // allValuesFrom = type constraint only, NO cardinality
   223→        // Do nothing
   224→      }
   225→      case DataSomeValuesFrom r -> schema.setMinItems(1);
   226→      case DataAllValuesFrom r -> { /* type constraint only */ }
   227→      default -> { /* other restrictions don't affect array cardinality */ }
